import React from 'react';

function Experience({ data }) {
  if (!data) return null;

  return (
    <section id="experience" className="py-12 md:py-16 bg-[#f6f1e7]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#7b7367] font-semibold mb-3">
            Experience
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#1d1c19]"
            style={{ fontFamily: '"Playfair Display", "Times New Roman", serif', fontWeight: 700 }}
          >
            Selected roles
          </h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-5">
          {data.map((exp, index) => (
            <article
              key={exp.id}
              className="rounded-3xl border border-[#ddd3c5] bg-white p-6 md:p-7 shadow-[0_14px_35px_rgba(17,17,17,0.06)] hover:-translate-y-0.5 transition-transform"
            >
              <p className="text-[10px] uppercase tracking-[0.35em] text-[#8d8477] mb-6">
                {String(index + 1).padStart(2, '0')}
              </p>

              <h3 className="text-xl font-black text-[#1f1d1a] mb-2 leading-tight">
                {exp.position}
              </h3>

              <p className="text-[10px] uppercase tracking-[0.28em] text-[#7b7367] mb-2">
                {exp.company}
              </p>

              <p className="text-sm text-[#8a8275] mb-4">{exp.period}</p>

              <p className="text-sm text-[#5f574d] leading-relaxed">
                {exp.description?.[0]}
              </p>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
